#!/usr/bin/env bash
# GHDL simulation for gnosis_resolution_lift_tb_v0 (optional gate).
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "$ROOT"

if [[ "${GNOSIS_RTL_TOOLS:-}" != "1" ]]; then
  echo "ghdl-sim-rtl-bridge: skip (set GNOSIS_RTL_TOOLS=1 and install ghdl to run)"
  exit 0
fi

if ! command -v ghdl >/dev/null 2>&1; then
  echo "ghdl-sim-rtl-bridge: ghdl not in PATH; skipping"
  exit 0
fi

cargo run --quiet --manifest-path "$ROOT/rtl-bridge/Cargo.toml" --bin gnosis-rtl-emit

VHDL_DIR="$ROOT/verifylog/vhdl"
WORKDIR="$ROOT/verifylog/traces/ghdl-work"
mkdir -p "$WORKDIR"
cd "$WORKDIR"
ghdl -a --std=08 "$VHDL_DIR/gnosis_resolution_lift_fsm_v0.vhd"
ghdl -a --std=08 "$VHDL_DIR/gnosis_resolution_lift_tb_v0.vhd"
ghdl -e --std=08 gnosis_resolution_lift_tb_v0
ghdl -r --std=08 gnosis_resolution_lift_tb_v0 2>&1 | tee "$ROOT/verifylog/traces/ghdl-resolution-lift.log"
echo "ghdl-sim-rtl-bridge: PASS (log: verifylog/traces/ghdl-resolution-lift.log)"
